#include <stdio.h>
#include <stdlib.h>

int cmp_int(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return (x > y) - (x < y);
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        scanf("%d", &N);
        int *arr = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        qsort(arr, N, sizeof(int), cmp_int);
        int maxFreq = 1, curFreq = 1;
        for (int i = 1; i < N; ++i) {
            if (arr[i] == arr[i-1]) {
                ++curFreq;
            } else {
                if (curFreq > maxFreq) maxFreq = curFreq;
                curFreq = 1;
            }
        }
        if (curFreq > maxFreq) maxFreq = curFreq;
        int ceilHalf = (N + 1) / 2;
        int ans = maxFreq > ceilHalf ? maxFreq : ceilHalf;
        printf("%d\n", ans);
        free(arr);
    }
    return 0;
}

